from __future__ import annotations

import math
import sys
import threading
from collections.abc import Awaitable, Callable, Generator
from contextlib import contextmanager
from contextvars import ContextVar, Token
from importlib import import_module
from typing import TYPE_CHECKING, Any, TypeVar

from ._exceptions import NoEventLoopError

if sys.version_info >= (3, 11):
    from typing import TypeVarTuple, Unpack
else:
    from typing_extensions import TypeVarTuple, Unpack

sniffio: Any
try:
    import sniffio
except ModuleNotFoundError:
    sniffio = None

if TYPE_CHECKING:
    from ..abc import AsyncBackend

# This must be updated when new backends are introduced
BACKENDS = "asyncio", "trio"

T_Retval = TypeVar("T_Retval")
PosArgsT = TypeVarTuple("PosArgsT")

threadlocals = threading.local()
loaded_backends: dict[str, type["AsyncBackend"]] = {}

_current_async_library: ContextVar[str | None] = ContextVar(
    "anyio_current_async_library", default=None
)


def run(
    func: Callable[[Unpack[PosArgsT]], Awaitable[T_Retval]],
    *args: Unpack[PosArgsT],
    backend: str = "asyncio",
    backend_options: dict[str, Any] | None = None,
) -> T_Retval:
    """
    Run the given coroutine function in an asynchronous event loop.

    The current thread must not be already running an event loop.

    :param func: a coroutine function
    :param args: positional arguments to ``func``
    :param backend: name of the asynchronous event loop implementation – currently
        either ``asyncio`` or ``trio``
    :param backend_options: keyword arguments to call the backend ``run()``
        implementation with (documented :ref:`here <backend options>`)
    :return: the return value of the coroutine function
    :raises RuntimeError: if an asynchronous event loop is already running in this
        thread
    :raises LookupError: if the named backend is not found

    """
    if asynclib_name := current_async_library():
        raise RuntimeError(f"Already running {asynclib_name} in this thread")

    try:
        async_backend = get_async_backend(backend)
    except ImportError as exc:
        raise LookupError(f"No such backend: {backend}") from exc

    token = None
    if asynclib_name is None:
        # Since we're in control of the event loop, we can cache the name of the async
        # library
        token = set_current_async_library(backend)

    try:
        backend_options = backend_options or {}
        return async_backend.run(func, args, {}, backend_options)
    finally:
        reset_current_async_library(token)


async def sleep(delay: float) -> None:
    """
    Pause the current task for the specified duration.

    :param delay: the duration, in seconds

    """
    return await get_async_backend().sleep(delay)


async def sleep_forever() -> None:
    """
    Pause the current task until it's cancelled.

    This is a shortcut for ``sleep(math.inf)``.

    .. versionadded:: 3.1

    """
    await sleep(math.inf)


async def sleep_until(deadline: float) -> None:
    """
    Pause the current task until the given time.

    :param deadline: the absolute time to wake up at (according to the internal
        monotonic clock of the event loop)

    .. versionadded:: 3.1

    """
    now = current_time()
    await sleep(max(deadline - now, 0))


def current_time() -> float:
    """
    Return the current value of the event loop's internal clock.

    :return: the clock value (seconds)
    :raises NoEventLoopError: if no supported asynchronous event loop is running in the
        current thread

    """
    return get_async_backend().current_time()


def get_all_backends() -> tuple[str, ...]:
    """Return a tuple of the names of all built-in backends."""
    return BACKENDS


def get_available_backends() -> tuple[str, ...]:
    """
    Test for the availability of built-in backends.

    :return a tuple of the built-in backend names that were successfully imported

    .. versionadded:: 4.12

    """
    available_backends: list[str] = []
    for backend_name in get_all_backends():
        try:
            get_async_backend(backend_name)
        except Exception:
            # If importing or initializing the backend fails, treat it as unavailable
            continue
        else:
            available_backends.append(backend_name)
    return tuple(available_backends)


@contextmanager
def claim_worker_thread() -> Generator[None, None, None]:
    """
    Context manager for claiming that the current thread is a worker thread.

    Some detection mechanisms (for example, sniffio) can detect an active event
    loop in a thread. Worker threads which are used to run blocking code and are not
    actually running an event loop should be able to opt out of that detection so
    that functions like current_async_library() do not report an active loop.

    Usage:
        with claim_worker_thread():
            # this thread is considered a worker thread within this block
            ...

    The previous state (whether the thread was considered a worker) is restored on
    exit.
    """
    previous = getattr(threadlocals, "worker_thread", False)
    threadlocals.worker_thread = True
    try:
        yield
    finally:
        threadlocals.worker_thread = previous


def get_async_backend(backend: str | None = None) -> type["AsyncBackend"]:
    """
    Return the AsyncBackend implementation class for the given backend name.

    If ``backend`` is None, the function will try to determine the currently
    active asynchronous library (via sniffio or an internally set override) and
    return the corresponding backend. If no backend can be determined, a
    NoEventLoopError is raised.

    The backend module is imported lazily and cached for subsequent calls.
    """
    if backend is None:
        backend = current_async_library()
        if backend is None:
            raise NoEventLoopError("No async library in current context")
    if backend in loaded_backends:
        return loaded_backends[backend]
    # Import the backend module as a relative import to this package.
    # Backend modules are expected to define an AsyncBackend class.
    module = import_module(f".{backend}", __name__)
    try:
        backend_cls = getattr(module, "AsyncBackend")
    except AttributeError as exc:
        raise ImportError(f"Backend module for {backend!r} has no AsyncBackend") from exc
    loaded_backends[backend] = backend_cls
    return backend_cls


def current_async_library() -> str | None:
    """
    Return the name of the currently running asynchronous library in this thread.

    The function first checks whether the current thread has been claimed as a
    worker thread via claim_worker_thread(); in that case, it returns None.
    Next it attempts to use sniffio.current_async_library() if sniffio is
    available. If sniffio is not available or cannot determine the library, an
    internally set value (via set_current_async_library) is returned if present.

    :return: the name of the async library (e.g. 'asyncio', 'trio'), or None if no
             async library is active or the thread is a claimed worker thread.
    """
    if getattr(threadlocals, "worker_thread", False):
        return None

    # Prefer sniffio if available
    if sniffio is not None:
        try:
            lib = sniffio.current_async_library()  # type: ignore[attr-defined]
        except Exception:
            lib = None
        if lib:
            return lib

    return _current_async_library.get()


def set_current_async_library(name: str) -> Token:
    """
    Set the current asynchronous library name for the context and return a token.

    This sets an internal context-local override so that current_async_library()
    and get_async_backend(None) can report the given library name even if
    sniffio is unavailable. The returned Token can be used with
    reset_current_async_library() to restore the previous value.
    """
    return _current_async_library.set(name)


def reset_current_async_library(token: Token | None) -> None:
    """
    Restore the previously set asynchronous library context using the given token.

    If token is None, nothing is done. Otherwise, the token previously returned by
    set_current_async_library() is used to reset the ContextVar to its prior state.
    """
    if token is not None:
        _current_async_library.reset(token)